function buildTags() {
  const tags = [];
  TAG_NAMES.forEach((n,i) => {
    let cat = "综合";
    if(n.match(/数据|分析|指标|KPI|SQL|pandas|Python/)) cat="数据分析";
    else if(n.match(/机器|学习|模型|训练|深度|强化/)) cat="机器学习";
    else if(n.match(/可视化|图表|看板|BI|plot|matplotlib/)) cat="可视化";
    tags.push({ id:`da-tag-${String(i+1).padStart(3,"0")}`, name:n, category:cat, description:`${cat}标签：${n}`, count:0, createdAt:"2026-07-01T00:00:00.000Z" });
  });
  return tags;
}

